import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import type { Notification, NotificationType } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetNotificationLogIdCounter();
  });

  function makeNotification(overrides: Partial<Notification> = {}): Notification {
    return {
      id: 'notif-0001',
      type: 'order_confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-0001',
      body: 'Your order has been placed.',
      sentAt: new Date('2026-03-29T12:00:00Z'),
      success: true,
      ...overrides,
    };
  }

  describe('log', () => {
    it('should log a successful notification', () => {
      const notification = makeNotification();
      const entry = historyService.log(notification);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.subject).toBe('Order Confirmation: order-0001');
      expect(entry.status).toBe('sent');
      expect(entry.error).toBeUndefined();
      expect(entry.createdAt).toEqual(new Date('2026-03-29T12:00:00Z'));
    });

    it('should log a failed notification with error', () => {
      const notification = makeNotification({
        success: false,
        error: 'Transport timeout',
      });
      const entry = historyService.log(notification);

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Transport timeout');
    });

    it('should generate sequential IDs', () => {
      const e1 = historyService.log(makeNotification({ id: 'notif-0001' }));
      const e2 = historyService.log(makeNotification({ id: 'notif-0002' }));
      const e3 = historyService.log(makeNotification({ id: 'notif-0003' }));

      expect(e1.id).toBe('nlog-0001');
      expect(e2.id).toBe('nlog-0002');
      expect(e3.id).toBe('nlog-0003');
    });

    it('should persist to repository', () => {
      historyService.log(makeNotification());
      expect(repository.count()).toBe(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log(makeNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        type: 'order_confirmation',
        channel: 'email',
        sentAt: new Date('2026-03-01T10:00:00Z'),
        success: true,
      }));
      historyService.log(makeNotification({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'welcome',
        channel: 'email',
        sentAt: new Date('2026-03-15T10:00:00Z'),
        success: true,
      }));
      historyService.log(makeNotification({
        id: 'notif-0003',
        recipient: 'alice@example.com',
        type: 'order_status_update',
        channel: 'webhook',
        sentAt: new Date('2026-03-20T10:00:00Z'),
        success: false,
        error: 'Connection refused',
      }));
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every(r => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0].recipient).toBe('bob@example.com');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0].type).toBe('order_status_update');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0].error).toBe('Connection refused');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        from: new Date('2026-03-10T00:00:00Z'),
        to: new Date('2026-03-16T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0].recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0].type).toBe('order_confirmation');
    });

    it('should return all when no filters', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('getByRecipient', () => {
    it('should return logs for a specific recipient', () => {
      historyService.log(makeNotification({ id: 'n1', recipient: 'alice@example.com' }));
      historyService.log(makeNotification({ id: 'n2', recipient: 'bob@example.com' }));

      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0].recipient).toBe('alice@example.com');
    });
  });

  describe('getByType', () => {
    it('should return logs for a specific type', () => {
      historyService.log(makeNotification({ id: 'n1', type: 'welcome' }));
      historyService.log(makeNotification({ id: 'n2', type: 'order_confirmation' }));

      const results = historyService.getByType('welcome');
      expect(results).toHaveLength(1);
      expect(results[0].type).toBe('welcome');
    });
  });

  describe('getByDateRange', () => {
    it('should return logs within a date range', () => {
      historyService.log(makeNotification({
        id: 'n1',
        sentAt: new Date('2026-01-01T00:00:00Z'),
      }));
      historyService.log(makeNotification({
        id: 'n2',
        sentAt: new Date('2026-06-15T00:00:00Z'),
      }));

      const results = historyService.getByDateRange(
        new Date('2026-06-01T00:00:00Z'),
        new Date('2026-06-30T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
    });
  });

  describe('getAll and count', () => {
    it('should return all entries', () => {
      historyService.log(makeNotification({ id: 'n1' }));
      historyService.log(makeNotification({ id: 'n2' }));

      expect(historyService.getAll()).toHaveLength(2);
      expect(historyService.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications when sent via NotificationService', async () => {
      await notificationService.send({
        type: 'welcome',
        recipient: 'test@example.com',
        subject: 'Welcome',
        body: 'Hello!',
      });

      expect(historyService.count()).toBe(1);
      const logs = historyService.getAll();
      expect(logs[0].recipient).toBe('test@example.com');
      expect(logs[0].type).toBe('welcome');
      expect(logs[0].channel).toBe('in_app');
      expect(logs[0].status).toBe('sent');
    });

    it('should log notifications through adapters', async () => {
      const mockAdapter = {
        channel: 'email' as const,
        send: async () => ({
          success: true,
          channel: 'email' as const,
          recipient: 'test@example.com',
          messageId: 'msg-001',
        }),
      };
      notificationService.registerAdapter(mockAdapter);

      await notificationService.send({
        type: 'order_confirmation',
        recipient: 'test@example.com',
        subject: 'Order Confirmed',
        body: 'Your order is confirmed.',
      });

      expect(historyService.count()).toBe(1);
      const logs = historyService.getAll();
      expect(logs[0].channel).toBe('email');
      expect(logs[0].status).toBe('sent');
    });

    it('should log failed notifications', async () => {
      const failingAdapter = {
        channel: 'webhook' as const,
        send: async () => ({
          success: false,
          channel: 'webhook' as const,
          recipient: 'test@example.com',
          error: 'Connection refused',
        }),
      };
      notificationService.registerAdapter(failingAdapter);

      await notificationService.send({
        type: 'welcome',
        recipient: 'test@example.com',
        subject: 'Welcome',
        body: 'Hello!',
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('failed');
      expect(logs[0].error).toBe('Connection refused');
    });

    it('should log through event-driven flow', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(1);
      const logs = historyService.getAll();
      expect(logs[0].type).toBe('welcome');
      expect(logs[0].recipient).toBe('alice@example.com');
    });

    it('should work without history service (backward compatible)', async () => {
      const standaloneService = new NotificationService(eventBus);
      // No historyService set — should not throw
      await standaloneService.send({
        type: 'welcome',
        recipient: 'test@example.com',
        subject: 'Welcome',
        body: 'Hello!',
      });

      expect(standaloneService.getNotificationCount()).toBe(1);
    });
  });
});
